text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "민준",
      "서연",
      "도윤",
      "하라"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 둔다."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "기각됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표일 뿐이며 최종 공개 릴리스 결정은 아님"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자와 확정 일정은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "민준",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "도윤",
      "task": "실패 시 대응을 위한 triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "하라",
      "task": "민준이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "대기",
      "source_certainty": "확정(기한 미정)"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토 여부와 담당자를 정한다.",
      "due": "목요일 가능 시",
      "status": "미할당",
      "source_certainty": "부분확정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 민준의 스모크 테스트 재실행 결과가 공유되었는지 확인한다.",
      "스모크 실패 시 도윤의 triage note 작성이 금요일 12:00 KST 기준으로 준비되는지 확인한다.",
      "민준의 결과 공유 이후 하라의 tarball 경로 점검이 실제 경로 문제를 해소하는지 확인한다.",
      "README 설치 단계 검토의 담당자 지정 여부와 실제 검토 필요성을 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트에 수요일 스트레치 목표를 적을지 여부를 별도 결정 사항으로 남긴다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "정해지지 않은 담당자",
      "정해지지 않은 기한",
      "결정되지 않은 승인 권한자"
    ]
  },
  "non_invention_rules": [
    "인라인 공개 안전 합성 fixture에 있는 사실만 사용한다.",
    "확정 결정과 제안, 기각안, 내부 스트레치 목표, 리스크, 미해결 질문을 섞지 않는다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무, 담당자, 기한 사실을 만들지 않는다.",
    "담당자나 기한이 없으면 null 또는 미정 상태로 유지한다.",
    "수요일 릴리스는 내부 스트레치 목표로만 기록하고 확정 공개 일정으로 승격하지 않는다."
  ]
}
